python3 -c "
import json
with open('/tmp/yoke-capture-5.jsonl') as f:
    for i, line in enumerate(f, 1):
        line = line.strip()
        if line:
            obj = json.loads(line)
            t = obj.get('type')
            st = obj.get('subtype', '')
            extra = ''
            if t == 'assistant':
                blocks = obj.get('message', {}).get('content', [])
                for b in blocks:
                    extra += b.get('type', '?') + ' '
            elif t == 'user':
                blocks = obj.get('message', {}).get('content', [])
                for b in blocks:
                    extra += b.get('type', '?') + ' '
            print(f'line {i}: {t} {st} | {extra}')
"

