/** Feed a fixture file line-by-line via feed() and collect all emitted events. */
function parseFixture(filename: string): StreamJsonEvent[] {
  const parser = new StreamJsonParser();
  const events: StreamJsonEvent[] = [];
  for (const evType of [
    'stream.text',
    'stream.thinking',
    'stream.tool_use',
    'stream.tool_result',
    'stream.usage',
    'stream.system_notice',
    'rate_limit_detected',
    'parse_error',
  ]) {
    parser.on(evType as Parameters<typeof parser.on>[0], (ev: StreamJsonEvent) =>
      events.push(ev),
    );
  }
  const content = readFileSync(join(FIXTURES, filename), 'utf8');
  for (const line of content.split('\n')) {
    parser.feed(line);
  }
  return events;
}

